components.css:
span.badge {
  display: inline-block;
  padding: var(--a-space-xs) var(--a-space-sm);
  background: var(--a-primary);
  color: var(--a-surface-base);
  border-radius: var(--a-radius-sm);
  font-size: var(--a-text-xs);
  font-weight: var(--a-font-weight-semibold);
}

.breadcrumb {
  display: flex;
  list-style: none;
  padding: 0;
  margin: 0;
  gap: var(--a-space-sm);
}

.breadcrumb li::before {
  content: '/';
  color: var(--a-text-muted);
}

.breadcrumb li:first-child::before {
  display: none;
}

.breadcrumb a {
  color: var(--a-primary);
  text-decoration: none;
}

.breadcrumb a:hover {
  text-decoration: underline;
}

.breadcrumb span[aria-current="page"] {
  color: var(--a-text-main);
  font-weight: var(--a-font-weight-medium);
}

.pagination {
  display: flex;
  list-style: none;
  padding: 0;
  margin: 0;
  gap: var(--a-space-xs);
}

.pagination a,
.pagination button {
  padding: var(--a-space-sm) var(--a-space-md);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  text-decoration: none;
  cursor: pointer;
  transition: all var(--a-transition-base);
}

.pagination a:hover,
.pagination button:hover {
  border-color: var(--a-primary);
  color: var(--a-primary);
}

.pagination a[aria-current="page"] {
  background: var(--a-primary);
  color: var(--a-surface-base);
  border-color: var(--a-primary);
  cursor: default;
}

button[role="tab"] {
  padding: var(--a-space-md) var(--a-space-lg);
  background: var(--a-surface-overlay);
  border: 1px solid var(--a-border);
  border-bottom: none;
  cursor: pointer;
  transition: all var(--a-transition-base);
}

button[role="tab"][aria-selected="true"] {
  background: var(--a-surface-base);
  border-bottom: 3px solid var(--a-primary);
}

section[role="tabpanel"] {
  padding: var(--a-space-lg);
  border: 1px solid var(--a-border);
  border-top: none;
}

button[data-tooltip]::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  padding: var(--a-space-xs) var(--a-space-sm);
  background: var(--a-text-main);
  color: var(--a-surface-base);
  border-radius: var(--a-radius-sm);
  font-size: var(--a-text-xs);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--a-transition-base);
}

button[data-tooltip]:hover::after {
  opacity: 1;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid var(--a-surface-overlay);
  border-top-color: var(--a-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

progress {
  width: 100%;
  height: 8px;
  border-radius: var(--a-radius-sm);
  border: none;
  background: var(--a-surface-overlay);
  overflow: hidden;
}

progress::-webkit-progress-bar {
  background: var(--a-surface-overlay);
}

progress::-webkit-progress-value {
  background: var(--a-primary);
  border-radius: var(--a-radius-sm);
}

progress::-moz-progress-bar {
  background: var(--a-primary);
  border-radius: var(--a-radius-sm);
}

.dropdown {
  position: relative;
}

.dropdown nav {
  position: absolute;
  top: 100%;
  left: 0;
  background: var(--a-surface-base);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  flex-direction: column;
  gap: 0;
}

.dropdown nav a {
  display: block;
  padding: var(--a-space-md) var(--a-space-lg);
  text-decoration: none;
  color: var(--a-text-main);
  transition: all var(--a-transition-base);
}

.dropdown nav a:hover {
  background: var(--a-surface-overlay);
  color: var(--a-primary);
}

.modal {
  border: none;
  border-radius: var(--a-radius-lg);
  padding: var(--a-space-2xl);
  max-width: 500px;
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
}

.modal::backdrop {
  background: rgba(0, 0, 0, 0.5);
}
